def count_unique(nums):
    """
    Returns the number of unique values that appear only once in the list.

    :param nums: A list of numbers
    :return: The number of unique single occurrence values
    """
    count_dict = {}
    for num in nums:
        if num in count_dict:
            count_dict[num] += 1
        else:
            count_dict[num] = 1

    return sum(val == 1 for val in count_dict.values())
